import React, { useState, useEffect, useRef, useCallback } from 'react';
import { useAuth } from '../../context/AuthContext';
import { useSocket } from '../../context/SocketContext';
import { getTheme, cardStyle } from '../../utils/theme';
import { PageHeader, Btn } from '../../components/common/UI';
import API from '../../utils/api';

const ICE_SERVERS = {
  iceServers: [
    { urls: 'stun:stun.l.google.com:19302' },
    { urls: 'stun:stun1.l.google.com:19302' },
  ],
};

export default function PatientVideoCall() {
  const { user, darkMode } = useAuth();
  const { socket } = useSocket();
  const t = getTheme(darkMode);

  const [phase, setPhase] = useState('lobby'); // lobby | waiting | in-call | ended
  const [muted, setMuted] = useState(false);
  const [videoOff, setVideoOff] = useState(false);
  const [elapsed, setElapsed] = useState(0);
  const [roomId, setRoomId] = useState(null);
  const [peerConnected, setPeerConnected] = useState(false);
  const [statusMsg, setStatusMsg] = useState('');

  const localVideoRef = useRef(null);
  const remoteVideoRef = useRef(null);
  const localStreamRef = useRef(null);
  const pcRef = useRef(null);
  const timerRef = useRef(null);
  const isInitiatorRef = useRef(false);

  const fmt = (s) => `${String(Math.floor(s / 60)).padStart(2, '0')}:${String(s % 60).padStart(2, '0')}`;

  // ── Peer Connection Setup ──────────────────────────────────────────────────
  const createPeerConnection = useCallback(() => {
    const pc = new RTCPeerConnection(ICE_SERVERS);

    pc.onicecandidate = ({ candidate }) => {
      if (candidate && socket && roomId) {
        socket.emit('webrtc:ice-candidate', { roomId, candidate });
      }
    };

    pc.ontrack = ({ streams }) => {
      if (remoteVideoRef.current && streams[0]) {
        remoteVideoRef.current.srcObject = streams[0];
        setPeerConnected(true);
        setStatusMsg('Doctor connected ✓');
      }
    };

    pc.onconnectionstatechange = () => {
      if (pc.connectionState === 'disconnected' || pc.connectionState === 'failed') {
        setStatusMsg('Connection lost. Reconnecting…');
        setPeerConnected(false);
      }
    };

    return pc;
  }, [socket, roomId]);

  // ── Socket Event Handlers ──────────────────────────────────────────────────
  useEffect(() => {
    if (!socket || !roomId) return;

    socket.on('webrtc:ready-to-call', async ({ initiator }) => {
      isInitiatorRef.current = initiator;
      if (initiator) {
        setStatusMsg('Waiting for doctor to join…');
      } else {
        setStatusMsg('Doctor is in the room — connecting…');
      }
    });

    socket.on('webrtc:peer-joined', async ({ userId, role }) => {
      setStatusMsg(`${role === 'doctor' ? 'Doctor' : 'Peer'} joined — establishing connection…`);
      if (isInitiatorRef.current && pcRef.current) {
        try {
          const offer = await pcRef.current.createOffer();
          await pcRef.current.setLocalDescription(offer);
          socket.emit('webrtc:offer', { roomId, offer });
        } catch (e) { setStatusMsg('Failed to create offer: ' + e.message); }
      }
    });

    socket.on('webrtc:offer', async ({ offer }) => {
      if (!pcRef.current) return;
      try {
        await pcRef.current.setRemoteDescription(new RTCSessionDescription(offer));
        const answer = await pcRef.current.createAnswer();
        await pcRef.current.setLocalDescription(answer);
        socket.emit('webrtc:answer', { roomId, answer });
      } catch (e) { setStatusMsg('Offer handling error: ' + e.message); }
    });

    socket.on('webrtc:answer', async ({ answer }) => {
      if (!pcRef.current) return;
      try {
        await pcRef.current.setRemoteDescription(new RTCSessionDescription(answer));
      } catch (e) { setStatusMsg('Answer error: ' + e.message); }
    });

    socket.on('webrtc:ice-candidate', async ({ candidate }) => {
      if (!pcRef.current) return;
      try { await pcRef.current.addIceCandidate(new RTCIceCandidate(candidate)); }
      catch { /* ignore stale candidates */ }
    });

    socket.on('webrtc:peer-left', () => {
      setPeerConnected(false);
      setStatusMsg('Doctor left the call.');
      if (remoteVideoRef.current) remoteVideoRef.current.srcObject = null;
    });

    return () => {
      socket.off('webrtc:ready-to-call');
      socket.off('webrtc:peer-joined');
      socket.off('webrtc:offer');
      socket.off('webrtc:answer');
      socket.off('webrtc:ice-candidate');
      socket.off('webrtc:peer-left');
    };
  }, [socket, roomId]);

  // ── Start Call ──────────────────────────────────────────────────────────────
  const startCall = async () => {
    try {
      setStatusMsg('Requesting camera & microphone…');
      const stream = await navigator.mediaDevices.getUserMedia({ video: true, audio: true });
      localStreamRef.current = stream;
      if (localVideoRef.current) localVideoRef.current.srcObject = stream;

      // Create room on backend
      const { data } = await API.post('/webrtc/room');
      const newRoomId = data.roomId;
      setRoomId(newRoomId);

      // Create peer connection
      const pc = createPeerConnection();
      stream.getTracks().forEach(track => pc.addTrack(track, stream));
      pcRef.current = pc;

      // Join signaling room
      if (socket) {
        socket.emit('webrtc:join', { roomId: newRoomId, userId: user._id, role: 'patient' });
      }

      setPhase('waiting');
      setStatusMsg('Room created. Share your Room ID with the doctor.');

      timerRef.current = setInterval(() => setElapsed(e => e + 1), 1000);
    } catch (e) {
      alert('Camera/microphone access required: ' + e.message);
    }
  };

  // ── Join Existing Room ──────────────────────────────────────────────────────
  const joinRoom = async (rid) => {
    try {
      const stream = await navigator.mediaDevices.getUserMedia({ video: true, audio: true });
      localStreamRef.current = stream;
      if (localVideoRef.current) localVideoRef.current.srcObject = stream;

      const pc = createPeerConnection();
      stream.getTracks().forEach(track => pc.addTrack(track, stream));
      pcRef.current = pc;

      setRoomId(rid);
      if (socket) socket.emit('webrtc:join', { roomId: rid, userId: user._id, role: 'patient' });
      setPhase('in-call');
      timerRef.current = setInterval(() => setElapsed(e => e + 1), 1000);
    } catch (e) { alert('Error joining room: ' + e.message); }
  };

  // ── End Call ────────────────────────────────────────────────────────────────
  const endCall = () => {
    localStreamRef.current?.getTracks().forEach(t => t.stop());
    pcRef.current?.close();
    if (socket && roomId) socket.emit('webrtc:leave', { roomId });
    if (timerRef.current) clearInterval(timerRef.current);
    pcRef.current = null;
    setPhase('ended');
    setMuted(false); setVideoOff(false); setElapsed(0);
    setPeerConnected(false);
  };

  const toggleMute = () => {
    localStreamRef.current?.getAudioTracks().forEach(t => { t.enabled = muted; });
    if (socket && roomId) socket.emit('webrtc:toggle-media', { roomId, audio: muted, video: !videoOff });
    setMuted(!muted);
  };

  const toggleVideo = () => {
    localStreamRef.current?.getVideoTracks().forEach(t => { t.enabled = videoOff; });
    if (socket && roomId) socket.emit('webrtc:toggle-media', { roomId, audio: !muted, video: videoOff });
    setVideoOff(!videoOff);
  };

  useEffect(() => () => { endCall(); }, []); // cleanup on unmount

  // ── When roomId is set from createPeerConnection closure update ─────────────
  useEffect(() => {
    if (phase === 'waiting') setPhase('in-call');
  }, [roomId]);

  return (
    <div style={{ background: t.bg, minHeight: '100vh', padding: 24 }}>
      <div style={{ maxWidth: 960, margin: '0 auto' }}>
        <PageHeader title="🎥 Video Consultation" subtitle="Peer-to-peer encrypted video call" darkMode={darkMode} />

        {/* LOBBY */}
        {phase === 'lobby' && (
          <div style={{ ...cardStyle(t), padding: 48, textAlign: 'center' }}>
            <div style={{ fontSize: '5rem', marginBottom: 20 }}>🎥</div>
            <h2 style={{ color: t.text, fontSize: 24, fontWeight: 800, marginBottom: 12 }}>Ready to Connect?</h2>
            <p style={{ color: t.textSub, marginBottom: 32, fontSize: 15 }}>
              Start a peer-to-peer WebRTC video consultation.<br />Your camera and microphone will be requested.
            </p>
            <div style={{ display: 'flex', gap: 16, justifyContent: 'center', flexWrap: 'wrap', marginBottom: 32 }}>
              {[['🔒', 'P2P Encrypted', 'Direct browser-to-browser'], ['🎙️', 'HD Audio', 'Crystal clear sound'], ['📡', 'WebRTC', 'No server relay needed']].map(([icon, label, desc]) => (
                <div key={label} style={{ background: darkMode ? 'rgba(255,255,255,0.06)' : '#f0f9ff', borderRadius: 14, padding: '16px 20px', minWidth: 140 }}>
                  <div style={{ fontSize: '2rem', marginBottom: 6 }}>{icon}</div>
                  <div style={{ fontWeight: 700, color: t.text, fontSize: 14 }}>{label}</div>
                  <div style={{ fontSize: 11, color: t.textSub }}>{desc}</div>
                </div>
              ))}
            </div>
            <Btn variant="primary" size="lg" onClick={startCall}>🎥 Start New Call</Btn>
          </div>
        )}

        {/* IN CALL */}
        {(phase === 'in-call' || phase === 'waiting') && (
          <div style={{ ...cardStyle(t), overflow: 'hidden' }}>
            {/* Status bar */}
            {statusMsg && (
              <div style={{ background: peerConnected ? '#dcfce7' : '#fef9c3', color: peerConnected ? '#166534' : '#854d0e', padding: '8px 16px', fontSize: 13, fontWeight: 600, textAlign: 'center' }}>
                {statusMsg}
              </div>
            )}

            {/* Room ID share */}
            {roomId && (
              <div style={{ padding: '10px 20px', background: darkMode ? '#1e293b' : '#f8fafc', borderBottom: `1px solid ${t.border}`, display: 'flex', alignItems: 'center', gap: 12 }}>
                <span style={{ color: t.textSub, fontSize: 13 }}>Room ID:</span>
                <code style={{ background: darkMode ? '#0f172a' : '#e0f2fe', color: '#0ea5e9', padding: '3px 10px', borderRadius: 6, fontSize: 12, fontFamily: 'monospace' }}>{roomId}</code>
                <button onClick={() => navigator.clipboard.writeText(roomId)} style={{ fontSize: 12, color: '#0ea5e9', background: 'none', border: 'none', cursor: 'pointer' }}>📋 Copy</button>
              </div>
            )}

            {/* Video grid */}
            <div style={{ background: '#0f172a', display: 'grid', gridTemplateColumns: '1fr 1fr', gap: 2, minHeight: 360 }}>
              {/* Local video */}
              <div style={{ position: 'relative', background: '#1e293b', display: 'flex', alignItems: 'center', justifyContent: 'center' }}>
                <video ref={localVideoRef} autoPlay muted style={{ width: '100%', height: '100%', objectFit: 'cover', transform: 'scaleX(-1)', display: videoOff ? 'none' : 'block', maxHeight: 400 }} />
                {videoOff && <div style={{ color: 'white', textAlign: 'center' }}><div style={{ fontSize: '3rem' }}>📷</div><p style={{ fontSize: 13 }}>Camera off</p></div>}
                <div style={{ position: 'absolute', bottom: 10, left: 10, background: 'rgba(0,0,0,0.6)', color: 'white', fontSize: 12, padding: '3px 8px', borderRadius: 6 }}>You {muted ? '🔇' : ''}</div>
              </div>
              {/* Remote video */}
              <div style={{ position: 'relative', background: '#0f172a', display: 'flex', alignItems: 'center', justifyContent: 'center' }}>
                <video ref={remoteVideoRef} autoPlay style={{ width: '100%', height: '100%', objectFit: 'cover', maxHeight: 400, display: peerConnected ? 'block' : 'none' }} />
                {!peerConnected && (
                  <div style={{ color: 'white', textAlign: 'center' }}>
                    <div style={{ fontSize: '3rem', marginBottom: 8 }}>👨‍⚕️</div>
                    <p style={{ fontSize: 13, color: '#94a3b8' }}>Waiting for doctor…</p>
                    <div style={{ width: 32, height: 32, border: '3px solid #0ea5e9', borderTopColor: 'transparent', borderRadius: '50%', animation: 'spin 1s linear infinite', margin: '10px auto' }} />
                  </div>
                )}
                {peerConnected && <div style={{ position: 'absolute', bottom: 10, left: 10, background: 'rgba(0,0,0,0.6)', color: 'white', fontSize: 12, padding: '3px 8px', borderRadius: 6 }}>Doctor</div>}
              </div>
            </div>

            {/* Controls */}
            <div style={{ background: '#1e293b', padding: '16px 24px', display: 'flex', alignItems: 'center', justifyContent: 'space-between' }}>
              <div style={{ color: '#94a3b8', fontSize: 14 }}>⏱️ {fmt(elapsed)}</div>
              <div style={{ display: 'flex', gap: 12 }}>
                <button onClick={toggleMute} style={{ width: 52, height: 52, borderRadius: '50%', border: 'none', background: muted ? '#ef4444' : 'rgba(255,255,255,0.15)', color: 'white', cursor: 'pointer', fontSize: 20 }}>{muted ? '🔇' : '🎙️'}</button>
                <button onClick={toggleVideo} style={{ width: 52, height: 52, borderRadius: '50%', border: 'none', background: videoOff ? '#ef4444' : 'rgba(255,255,255,0.15)', color: 'white', cursor: 'pointer', fontSize: 20 }}>{videoOff ? '📷' : '🎥'}</button>
                <button onClick={endCall} style={{ padding: '0 24px', height: 52, borderRadius: 26, border: 'none', background: '#ef4444', color: 'white', cursor: 'pointer', fontSize: 14, fontWeight: 700 }}>📵 End Call</button>
              </div>
              <div style={{ color: peerConnected ? '#10b981' : '#f59e0b', fontSize: 13, fontWeight: 700 }}>
                {peerConnected ? '● Connected' : '○ Waiting'}
              </div>
            </div>
          </div>
        )}

        {/* ENDED */}
        {phase === 'ended' && (
          <div style={{ ...cardStyle(t), padding: 48, textAlign: 'center' }}>
            <div style={{ fontSize: '4rem', marginBottom: 16 }}>✅</div>
            <h2 style={{ color: t.text, fontWeight: 800, marginBottom: 8 }}>Call Ended</h2>
            <p style={{ color: t.textSub, marginBottom: 8 }}>Duration: {fmt(elapsed)}</p>
            <Btn variant="primary" onClick={() => { setPhase('lobby'); setElapsed(0); setRoomId(null); }}>Start New Call</Btn>
          </div>
        )}
        <style>{`@keyframes spin { to { transform: rotate(360deg); } }`}</style>
      </div>
    </div>
  );
}
